def process_file(filepath):
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()
    original = content
    count = 0
    for en_text, translations in T.items():
        for lang in ['ta', 'te', 'bn', 'kn', 'gu']:
            if lang not in translations:
                continue
            real_trans = translations[lang]
            for quote in ["'", '"']:
                old = f"{lang}: {quote}{en_text}{quote}"
                new = f"{lang}: {quote}{real_trans}{quote}"
                if old in content and old != new:
                    content = content.replace(old, new)
                    count += 1
    if content != original:
        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(content)
    return count

if __name__ == '__main__':
    total = 0
    for f in FILES:
        n = process_file(f)
        print(f'{f}: {n} replacements')
        total += n
    print(f'\nTotal: {total} replacements')
